 22→    pub authority: Signer<'info>,
 23→    pub registered_program_pda: Option<Account<'info, RegisteredProgram>>,
 24→    #[account(mut)]
 25→    pub queue: AccountLoader<'info, QueueAccount>,
 26→    #[account(mut)]
 27→    pub merkle_tree: AccountLoader<'info, AddressMerkleTreeAccount>,
 28→    /// CHECK: when emitting event.
 29→    pub log_wrapper: UncheckedAccount<'info>,
 30→    /// CHECK: receives network fee reimbursement.
 31→    #[account(mut)]
 32→    pub fee_payer: Option<UncheckedAccount<'info>>,
 33→}
