 44→#[allow(clippy::too_many_arguments)]
 45→pub fn process_update_address_merkle_tree<'info>(
 46→    ctx: Context<'_, '_, '_, 'info, UpdateAddressMerkleTree<'info>>,
 47→    // Index of the Merkle tree changelog.
 48→    changelog_index: u16,
 49→    indexed_changelog_index: u16,
 50→    // Address to dequeue.
 51→    value_index: u16,
 52→    // Low address.
 53→    low_address_value: [u8; 32],       // included in leaf hash
 54→    low_address_next_index: u64,       // included in leaf hash
 55→    low_address_next_value: [u8; 32],  // included in leaf hash
 56→    low_address_index: u64,            // leaf index of low element
 57→    low_address_proof: [[u8; 32]; 16], // Merkle proof for updating the low address.
 58→) -> Result<()> {
 59→    let address_queue = ctx.accounts.queue.to_account_info();
 60→    let mut address_queue = address_queue.try_borrow_mut_data()?;
 61→    let mut address_queue = unsafe { queue_from_bytes_zero_copy_mut(&mut address_queue)? };
 62→
 63→    let network_fee = {
 64→        let merkle_tree = ctx.accounts.merkle_tree.load_mut()?;
 65→        if merkle_tree.metadata.associated_queue != ctx.accounts.queue.key() {
 66→            msg!(
 67→            "Merkle tree and nullifier queue are not associated. Merkle tree associated address queue {:?} != provided queue {}",
 68→            merkle_tree.metadata.associated_queue,
 69→            ctx.accounts.queue.key()
 70→        );
 71→            return err!(AccountCompressionErrorCode::MerkleTreeAndQueueNotAssociated);
 72→        }
 73→        check_signer_is_registered_or_authority::<UpdateAddressMerkleTree, AddressMerkleTreeAccount>(
 74→            &ctx,
 75→            &merkle_tree,
 76→        )?;
 77→        merkle_tree.metadata.rollover_metadata.network_fee
 78→    };
 79→
 80→    let merkle_tree = ctx.accounts.merkle_tree.to_account_info();
 81→    let mut merkle_tree = merkle_tree.try_borrow_mut_data()?;
 82→    let mut merkle_tree = address_merkle_tree_from_bytes_zero_copy_mut(&mut merkle_tree)?;
 83→
 84→    let value = address_queue
 85→        .get_unmarked_bucket(value_index as usize)
 86→        .ok_or(AccountCompressionErrorCode::LeafNotFound)?
 87→        .ok_or(AccountCompressionErrorCode::LeafNotFound)?
 88→        .value_biguint();
 89→
 90→    // Indexed Merkle tree update:
 91→    // - the range represented by the low element is split into two ranges
 92→    // - the new low element(lower range, next value is address) and the address
 93→    //   element (higher range, next value is low_element.next_value)
 94→    // - the new low element is updated, and the address element is appended
 95→
 96→    // Lower range
