150→    pub fn set_rollover_fee(&mut self, ix_data_index: u8, fee: u64) {
151→        let payment = self
152→            .rollover_fee_payments
153→            .iter_mut()
154→            .find(|a| a.0 == ix_data_index);
155→        match payment {
156→            Some(payment) => payment.1 += fee,
157→            None => self.rollover_fee_payments.push((ix_data_index, fee)),
158→        };
159→    }
