186→pub struct WrappedInstructionData<'a, T: InstructionData<'a>> {
187→    instruction_data: T,
188→    cpi_context: Option<ZCpiContextAccount2<'a>>,
189→    address_len: usize,
190→    input_len: usize,
191→    outputs_len: usize,
192→    /// Offsets are used to copy output compressed account data from the cpi context
193→    /// to the system program -> account compression program cpi instruction data.
194→    /// This ensures the indexer can index all output account data.
195→    cpi_context_outputs_start_offset: usize,
196→    cpi_context_outputs_end_offset: usize,
197→}
198→
199→impl<'a, 'b, T> WrappedInstructionData<'a, T>
200→where
201→    T: InstructionData<'a>,
202→{
203→    #[profile]
204→    pub fn new(instruction_data: T) -> std::result::Result<Self, SystemProgramError> {
205→        let outputs_len = instruction_data
206→            .output_accounts()
207→            .iter()
208→            .filter(|x| !x.skip())
209→            .count();
210→        if outputs_len > MAX_OUTPUT_ACCOUNTS {
211→            return Err(SystemProgramError::TooManyOutputAccounts);
212→        }
213→        Ok(Self {
214→            input_len: instruction_data
215→                .input_accounts()
216→                .iter()
217→                .filter(|x| !x.skip())
218→                .count(),
219→            outputs_len,
220→            address_len: instruction_data.new_addresses().len(),
221→            cpi_context: None,
222→            instruction_data,
223→            cpi_context_outputs_start_offset: 0,
224→            cpi_context_outputs_end_offset: 0,
225→        })
226→    }
227→
228→    #[profile]
229→    pub fn set_cpi_context(&mut self, cpi_context: ZCpiContextAccount2<'a>) -> Result<()> {
230→        if self.cpi_context.is_none() {
231→            self.outputs_len += cpi_context.out_accounts.len();
232→            if self.outputs_len > MAX_OUTPUT_ACCOUNTS {
233→                return Err(SystemProgramError::TooManyOutputAccounts.into());
234→            }
235→            self.address_len += cpi_context.new_addresses.len();
236→            self.input_len += cpi_context.in_accounts.len();
237→
238→            // Calculate offsets from the CPI context account
239→            let (outputs_start_offset, outputs_end_offset) = cpi_context.calculate_output_offsets();
240→
241→            self.cpi_context = Some(cpi_context);
242→            self.cpi_context_outputs_start_offset = outputs_start_offset;
243→            self.cpi_context_outputs_end_offset = outputs_end_offset;
244→        } else {
245→            return Err(SystemProgramError::CpiContextAlreadySet.into());
246→        }
247→        Ok(())
248→    }
249→
250→    pub fn get_cpi_context_outputs_start_offset(&self) -> usize {
251→        self.cpi_context_outputs_start_offset
252→    }
253→
254→    pub fn get_cpi_context_outputs_end_offset(&self) -> usize {
255→        self.cpi_context_outputs_end_offset
256→    }
257→
258→    pub fn get_cpi_context_account(&'b self) -> &'b Option<ZCpiContextAccount2<'a>> {
259→        &self.cpi_context
260→    }
261→
262→    pub fn address_len(&self) -> usize {
263→        self.address_len
264→    }
265→
266→    pub fn input_len(&self) -> usize {
267→        self.input_len
268→    }
269→
270→    pub fn output_len(&self) -> usize {
271→        self.outputs_len
272→    }
273→
274→    pub fn inputs_empty(&self) -> bool {
275→        self.input_len == 0
276→    }
277→
278→    pub fn outputs_empty(&self) -> bool {
279→        self.outputs_len == 0
280→    }
281→
282→    pub fn address_empty(&self) -> bool {
283→        self.address_len == 0
284→    }
285→    pub fn bump(&self) -> Option<u8> {
286→        self.instruction_data.bump()
287→    }
288→
289→    pub fn with_transaction_hash(&self) -> bool {
290→        self.instruction_data.with_transaction_hash()
291→    }
292→
293→    #[profile]
294→    pub fn get_output_account(&'b self, index: usize) -> Option<&'b (dyn OutputAccount<'a> + 'b)> {
295→        // Check CPI context first
296→        if let Some(cpi_context) = self.cpi_context.as_ref() {
297→            let cpi_outputs_len = cpi_context.output_accounts().len();
298→            if index < cpi_outputs_len {
299→                return cpi_context.output_accounts().get(index).map(|account| {
300→                    let output_account_trait_object: &'b (dyn OutputAccount<'a> + 'b) = account;
301→                    output_account_trait_object
302→                });
303→            }
304→            // Adjust index for instruction data
305→            let ix_index = index - cpi_outputs_len;
306→            return self
307→                .instruction_data
308→                .output_accounts()
309→                .get(ix_index)
310→                .map(|account| account as &(dyn OutputAccount<'a> + 'b));
311→        }
312→
313→        // No CPI context, use instruction data
314→        self.instruction_data
315→            .output_accounts()
316→            .get(index)
317→            .map(|account| account as &(dyn OutputAccount<'a> + 'b))
318→    }
319→}
