355→        if let Some(cpi_context) = &self.cpi_context {
356→            chain_outputs(
357→                cpi_context.output_accounts(),
358→                self.instruction_data.output_accounts(),
359→            )
360→        } else {
361→            chain_outputs(&[], self.instruction_data.output_accounts())
362→        }
363→    }
