 5→pub fn transfer_lamports<'info>(
 6→    from: &AccountInfo<'info>,
 7→    to: &AccountInfo<'info>,
 8→    lamports: u64,
 9→) -> Result<()> {
10→    let compressed_sol_pda_lamports = from.lamports();
11→
12→    **from.as_ref().try_borrow_mut_lamports()? =
13→        match compressed_sol_pda_lamports.checked_sub(lamports) {
14→            Some(lamports) => lamports,
15→            None => return err!(AccountCompressionErrorCode::IntegerOverflow),
16→        };
17→    let recipient_lamports = to.lamports();
18→    **to.as_ref().try_borrow_mut_lamports()? = match recipient_lamports.checked_add(lamports) {
19→        Some(lamports) => lamports,
20→        None => return err!(AccountCompressionErrorCode::IntegerOverflow),
21→    };
22→    Ok(())
23→}
