150→    pub fn set_rollover_fee(&mut self, ix_data_index: u8, fee: u64) {
151→        let payment = self
152→            .rollover_fee_payments
153→            .iter_mut()
154→            .find(|a| a.0 == ix_data_index);
155→        match payment {
156→            Some(payment) => payment.1 += fee,
157→            None => self.rollover_fee_payments.push((ix_data_index, fee)),
158→        };
159→    }
160→
161→    /// Network fee distribution (fees read from tree metadata as `network_fee`):
162→    /// - V1 state trees: network_fee per input + network_fee per output (currently 5000 lamports each)
163→    /// - V2 batched state trees: network_fee once per tree if inputs > 0 OR outputs > 0 (currently 5000 lamports)
164→    /// - Address creation: network_fee per address (currently 10000 lamports each)
165→    ///
166→    /// Examples (V1 state trees, state network_fee=5000, address network_fee=10000):
167→    /// 1. create account (0 inputs, 1 output, 1 address):      0*5000 + 1*5000 + 1*10000 = 15,000 lamports
168→    /// 2. token transfer (1 input, 1 output, same tree):        1*5000 + 1*5000           = 10,000 lamports
169→    /// 3. transfer with 2 inputs, 1 output, 1 address:          2*5000 + 1*5000 + 1*10000 = 25,000 lamports
170→    ///
171→    /// Examples (V2 batched state trees, state network_fee=5000, address network_fee=10000):
172→    /// 1. token transfer (1 input, 0 output):          5,000 lamports (once per tree)
173→    /// 2. token transfer (0 input, 1 output):          5,000 lamports (once per tree)
174→    /// 3. token transfer (1 input, 1 output):          5,000 lamports (once per tree)
175→    /// 4. transfer with 2 inputs, 1 address:           5000 + 1*10000 = 15,000 lamports
176→    ///    Transfers rollover and network fees.
177→    pub fn transfer_fees(&self, accounts: &[AccountInfo], fee_payer: &AccountInfo) -> Result<()> {
178→        for (i, fee) in self.rollover_fee_payments.iter() {
179→            transfer_lamports_invoke(fee_payer, &accounts[*i as usize], *fee)?;
180→        }
181→        Ok(())
182→    }
