294→    pub fn get_output_account(&'b self, index: usize) -> Option<&'b (dyn OutputAccount<'a> + 'b)> {
295→        // Check CPI context first
296→        if let Some(cpi_context) = self.cpi_context.as_ref() {
297→            let cpi_outputs_len = cpi_context.output_accounts().len();
298→            if index < cpi_outputs_len {
299→                return cpi_context.output_accounts().get(index).map(|account| {
300→                    let output_account_trait_object: &'b (dyn OutputAccount<'a> + 'b) = account;
301→                    output_account_trait_object
302→                });
303→            }
304→            // Adjust index for instruction data
305→            let ix_index = index - cpi_outputs_len;
306→            return self
307→                .instruction_data
308→                .output_accounts()
309→                .get(ix_index)
310→                .map(|account| account as &(dyn OutputAccount<'a> + 'b));
311→        }
312→
313→        // No CPI context, use instruction data
314→        self.instruction_data
315→            .output_accounts()
316→            .get(index)
317→            .map(|account| account as &(dyn OutputAccount<'a> + 'b))
318→    }
