28→pub fn get_queue_and_tree_accounts<'b, 'info>(
29→    accounts: &'b mut [AcpAccount<'info>],
30→    queue_index: usize,
31→    tree_index: usize,
32→) -> std::result::Result<(&'b mut AcpAccount<'info>, &'b mut AcpAccount<'info>), SystemProgramError>
33→{
34→    let (smaller, bigger) = if queue_index < tree_index {
35→        (queue_index, tree_index)
36→    } else {
37→        (tree_index, queue_index)
38→    };
39→    let (left, right) = accounts.split_at_mut(bigger);
40→    let smaller_ref = &mut left[smaller];
41→    let bigger_ref = &mut right[0];
42→    Ok(if queue_index < tree_index {
43→        (smaller_ref, bigger_ref)
44→    } else {
45→        (bigger_ref, smaller_ref)
46→    })
47→}
