 63→#[inline(always)]
 64→#[profile]
 65→pub(crate) fn try_from_account_info<'a, 'info: 'a>(
 66→    account_info: &'info AccountInfo,
 67→    context: &mut SystemContext<'info>,
 68→    index: u8,
 69→) -> std::result::Result<AcpAccount<'info>, SystemProgramError> {
 70→    let mut discriminator = [0u8; 8];
 71→    {
 72→        let data = account_info
 73→            .try_borrow_data()
 74→            .map_err(|_| SystemProgramError::BorrowingDataFailed)?;
 75→
 76→        if data.len() < 8 {
 77→            return Ok(AcpAccount::Unknown());
 78→        }
 79→        discriminator.copy_from_slice(&data[..8]);
 80→    }
 81→
 82→    let (account, program_owner) = match discriminator {
 83→        BatchedMerkleTreeAccount::LIGHT_DISCRIMINATOR => {
 84→            let mut tree_type = [0u8; 8];
 85→            tree_type.copy_from_slice(
 86→                &account_info
 87→                    .try_borrow_data()
 88→                    .map_err(|_| SystemProgramError::BorrowingDataFailed)?[8..16],
 89→            );
 90→            let tree_type = TreeType::from(u64::from_le_bytes(tree_type));
 91→            match tree_type {
 92→                TreeType::AddressV2 => {
 93→                    let tree = BatchedMerkleTreeAccount::address_from_account_info(account_info)?;
 94→                    let program_owner = tree.metadata.access_metadata.program_owner;
 95→                    // for batched trees we set the fee when setting the rollover fee.
 96→                    Ok((AcpAccount::BatchedAddressTree(tree), program_owner))
 97→                }
 98→                TreeType::StateV2 => {
 99→                    let tree = BatchedMerkleTreeAccount::state_from_account_info(account_info)?;
100→                    let program_owner = tree.metadata.access_metadata.program_owner;
101→                    Ok((AcpAccount::BatchedStateTree(tree), program_owner))
102→                }
103→                _ => {
104→                    msg!(format!(
105→                        "Invalid batched tree type. {:?} pubkey: {:?}",
106→                        tree_type,
107→                        account_info.key()
108→                    )
109→                    .as_str());
110→                    Err(SystemProgramError::InvalidAccount)
111→                }
112→            }
113→        }
114→        BatchedQueueAccount::LIGHT_DISCRIMINATOR => {
115→            let queue = BatchedQueueAccount::output_from_account_info(account_info)?;
116→            let program_owner = queue.metadata.access_metadata.program_owner;
117→            Ok((AcpAccount::OutputQueue(queue), program_owner))
118→        }
119→        STATE_MERKLE_TREE_ACCOUNT_DISCRIMINATOR => {
120→            let program_owner = {
121→                check_owner(&ACCOUNT_COMPRESSION_PROGRAM_ID, account_info)?;
122→                let data = account_info
123→                    .try_borrow_data()
124→                    .map_err(|_| SystemProgramError::BorrowingDataFailed)?;
125→                let merkle_tree = bytemuck::from_bytes::<StateMerkleTreeAccount>(
126→                    &data[8..StateMerkleTreeAccount::LEN],
127→                );
128→                context.set_legacy_merkle_context(
129→                    index,
130→                    MerkleTreeContext {
131→                        rollover_fee: merkle_tree.metadata.rollover_metadata.rollover_fee,
132→                        hashed_pubkey: hash_to_bn254_field_size_be(account_info.key().as_slice()),
133→                        network_fee: merkle_tree.metadata.rollover_metadata.network_fee,
134→                    },
135→                );
136→
137→                merkle_tree.metadata.access_metadata.program_owner
138→            };
139→            let merkle_tree = account_info.try_borrow_mut_data();
140→            if merkle_tree.is_err() {
141→                return Err(SystemProgramError::InvalidAccount);
142→            }
143→            let merkle_tree = &mut merkle_tree.map_err(|_| SystemProgramError::InvalidAccount)?;
144→            // SAFETY: merkle_tree is a valid RefMut<[u8]>, pointer and length are valid
145→            let data_slice: &'info mut [u8] = unsafe {
146→                std::slice::from_raw_parts_mut(merkle_tree.as_mut_ptr(), merkle_tree.len())
147→            };
148→            Ok((
149→                AcpAccount::StateTree((
150→                    (*account_info.key()).into(),
151→                    state_merkle_tree_from_bytes_zero_copy_mut(data_slice)
152→                        .map_err(|e| SystemProgramError::ProgramError(e.into()))?,
153→                )),
154→                program_owner,
155→            ))
156→        }
157→        ADDRESS_MERKLE_TREE_ACCOUNT_DISCRIMINATOR => {
158→            let program_owner = {
159→                check_owner(&ACCOUNT_COMPRESSION_PROGRAM_ID, account_info)?;
160→                let data = account_info
161→                    .try_borrow_data()
162→                    .map_err(|_| SystemProgramError::BorrowingDataFailed)?;
163→
164→                let merkle_tree = bytemuck::from_bytes::<AddressMerkleTreeAccount>(
165→                    &data[8..AddressMerkleTreeAccount::LEN],
166→                );
167→                context.set_legacy_merkle_context(
168→                    index,
169→                    MerkleTreeContext {
170→                        rollover_fee: merkle_tree.metadata.rollover_metadata.rollover_fee,
171→                        hashed_pubkey: [0u8; 32], // not used for address trees
172→                        network_fee: merkle_tree.metadata.rollover_metadata.network_fee,
173→                    },
174→                );
175→                merkle_tree.metadata.access_metadata.program_owner
176→            };
177→            let mut merkle_tree = account_info
178→                .try_borrow_mut_data()
179→                .map_err(|_| SystemProgramError::InvalidAccount)?;
180→            // SAFETY: merkle_tree is a valid RefMut<[u8]>, pointer and length are valid
181→            let data_slice: &'info mut [u8] = unsafe {
182→                std::slice::from_raw_parts_mut(merkle_tree.as_mut_ptr(), merkle_tree.len())
183→            };
184→            Ok((
185→                AcpAccount::AddressTree((
186→                    (*account_info.key()).into(),
187→                    address_merkle_tree_from_bytes_zero_copy_mut(data_slice)
188→                        .map_err(|e| SystemProgramError::ProgramError(e.into()))?,
189→                )),
190→                program_owner,
191→            ))
192→        }
193→        QUEUE_ACCOUNT_DISCRIMINATOR => {
194→            check_owner(&ACCOUNT_COMPRESSION_PROGRAM_ID, account_info)?;
195→            let data = account_info
196→                .try_borrow_data()
197→                .map_err(|_| SystemProgramError::BorrowingDataFailed)?;
198→            let queue = bytemuck::from_bytes::<QueueAccount>(&data[8..QueueAccount::LEN]);
199→
200→            if queue.metadata.queue_type == QueueType::AddressV1 as u64 {
201→                context.set_legacy_merkle_context(
202→                    index,
203→                    MerkleTreeContext {
204→                        rollover_fee: queue.metadata.rollover_metadata.rollover_fee,
205→                        hashed_pubkey: [0u8; 32], // not used for address trees
206→                        network_fee: queue.metadata.rollover_metadata.network_fee,
207→                    },
208→                );
209→
210→                let program_owner = queue.metadata.access_metadata.program_owner;
211→                Ok((
212→                    AcpAccount::AddressQueue((*account_info.key()).into(), account_info),
213→                    program_owner,
214→                ))
215→            } else if queue.metadata.queue_type == QueueType::NullifierV1 as u64 {
216→                Ok((AcpAccount::V1Queue(account_info), Pubkey::default()))
217→            } else {
218→                msg!(format!(
219→                    "Invalid queue account {:?} type {}",
220→                    account_info.key(),
221→                    queue.metadata.queue_type
222→                )
223→                .as_str());
224→                Err(SystemProgramError::InvalidAccount)
225→            }
226→        }
227→        // Needed for compatibility with the token program.
228→        _ => Ok((AcpAccount::Unknown(), Pubkey::default())),
229→    }?;
230→
231→    if let AcpAccount::Unknown() = account {
232→        return Ok(account);
233→    }
234→    if !account_info.is_owned_by(&ACCOUNT_COMPRESSION_PROGRAM_ID) {
235→        msg!(format!("Pubkey {:?}", account_info.key()).as_str());
236→        return Err(SystemProgramError::InvalidAccount);
237→    }
238→
239→    if program_owner != Pubkey::default() {
240→        if let Some(invoking_program) = context.invoking_program_id {
241→            if invoking_program != program_owner.to_bytes() {
242→                msg!(format!(
243→                    "invoking_program.key() {:?} == merkle_tree_unpacked.program_owner {:?}",
244→                    invoking_program, program_owner
245→                )
246→                .as_str());
247→                return Err(SystemProgramError::InvalidMerkleTreeOwner);
248→            }
249→        } else {
250→            return Err(SystemProgramError::InvalidMerkleTreeOwner);
251→        }
252→    }
253→
254→    Ok(account)
255→}
