119→#[inline(never)]
120→fn insert_nullifier<'a, 'c: 'info, 'info>(
121→    proofs: &[Vec<[u8; 32]>],
122→    change_log_indices: &[u64],
123→    leaves_queue_indices: &[u16],
124→    leaf_indices: &[u64],
125→    ctx: &Context<'a, '_, 'c, 'info, NullifyLeaves<'info>>,
126→) -> Result<()> {
127→    {
128→        let merkle_tree = ctx.accounts.merkle_tree.load()?;
129→
130→        if merkle_tree.metadata.associated_queue != ctx.accounts.nullifier_queue.key() {
131→            msg!(
132→            "Merkle tree and nullifier queue are not associated. Merkle tree associated nullifier queue {:?} != nullifier queue {}",
133→            merkle_tree.metadata.associated_queue,
134→            ctx.accounts.nullifier_queue.key()
135→        );
136→            return err!(AccountCompressionErrorCode::MerkleTreeAndQueueNotAssociated);
137→        }
138→        check_signer_is_registered_or_authority::<NullifyLeaves, StateMerkleTreeAccount>(
139→            ctx,
140→            &merkle_tree,
141→        )?;
142→    }
143→
144→    let merkle_tree = ctx.accounts.merkle_tree.to_account_info();
145→    let mut merkle_tree = merkle_tree.try_borrow_mut_data()?;
146→    let mut merkle_tree = state_merkle_tree_from_bytes_zero_copy_mut(&mut merkle_tree)?;
147→
148→    let nullifier_queue = ctx.accounts.nullifier_queue.to_account_info();
149→    let mut nullifier_queue = nullifier_queue.try_borrow_mut_data()?;
150→    let mut nullifier_queue = unsafe { queue_from_bytes_zero_copy_mut(&mut nullifier_queue)? };
151→
152→    let allowed_proof_size = merkle_tree.height - merkle_tree.canopy_depth;
153→    if proofs[0].len() != allowed_proof_size {
154→        msg!(
155→            "Invalid Proof Length {} allowed height {} - canopy {} {}",
156→            proofs[0].len(),
157→            merkle_tree.height,
158→            merkle_tree.canopy_depth,
159→            allowed_proof_size,
160→        );
161→        return err!(AccountCompressionErrorCode::InvalidMerkleProof);
162→    }
163→    let seq = (merkle_tree.sequence_number() + 1) as u64;
164→    for (i, leaf_queue_index) in leaves_queue_indices.iter().enumerate() {
165→        let leaf_cell = nullifier_queue
166→            .get_unmarked_bucket(*leaf_queue_index as usize)
167→            .ok_or(AccountCompressionErrorCode::LeafNotFound)?
168→            .ok_or(AccountCompressionErrorCode::LeafNotFound)?;
169→
170→        let mut proof =
171→            from_vec(proofs[i].as_slice(), merkle_tree.height).map_err(ProgramError::from)?;
172→        merkle_tree
173→            .update(
174→                change_log_indices[i] as usize,
175→                &leaf_cell.value_bytes(),
176→                &ZERO_BYTES[0],
177→                leaf_indices[i] as usize,
178→                &mut proof,
179→            )
180→            .map_err(ProgramError::from)?;
181→
182→        nullifier_queue
183→            .mark_with_sequence_number(*leaf_queue_index as usize, merkle_tree.sequence_number())
184→            .map_err(ProgramError::from)?;
185→    }
186→    let nullify_event = NullifierEvent {
187→        id: ctx.accounts.merkle_tree.key().to_bytes(),
188→        nullified_leaves_indices: leaf_indices.to_vec(),
189→        seq,
190→    };
191→    let nullify_event = MerkleTreeEvent::V2(nullify_event);
192→    emit_indexer_event(nullify_event.try_to_vec()?, &ctx.accounts.log_wrapper)?;
193→    Ok(())
194→}
