196→#[inline(never)]
197→pub fn from_vec(vec: &[[u8; 32]], height: usize) -> Result<BoundedVec<[u8; 32]>> {
198→    let proof: [[u8; 32]; 16] = vec.try_into().unwrap();
199→    let mut bounded_vec = BoundedVec::with_capacity(height);
200→    bounded_vec.extend(proof).map_err(ProgramError::from)?;
201→    Ok(bounded_vec)
202→}
