 44→/// Check compressed_accounts in the queue array which are not nullified yet
 45→/// Iterate over these compressed_accounts and nullify them
 46→///
 47→/// Checks:
 48→/// 1. Value in hashset is marked
 49→/// 2. State tree root is updated
 50→/// 3. TODO: add event is emitted (after rebase)
 51→///    optional: assert that the Merkle tree doesn't change except the updated leaf
 52→pub async fn nullify_compressed_accounts<R: Rpc + TestRpc + Indexer + Indexer>(
 53→    rpc: &mut R,
 54→    forester: &Keypair,
 55→    state_tree_bundle: &mut StateMerkleTreeBundle,
 56→    epoch: u64,
 57→    is_metadata_forester: bool,
 58→) -> Result<(), RpcError> {
 59→    let nullifier_queue = unsafe {
 60→        get_hash_set::<QueueAccount, R>(rpc, state_tree_bundle.accounts.nullifier_queue).await
 61→    }
 62→    .unwrap();
 63→    let pre_forester_counter = if is_metadata_forester {
 64→        0
 65→    } else {
 66→        rpc.get_anchor_account::<ForesterEpochPda>(
 67→            &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
 68→        )
 69→        .await
 70→        .unwrap()
 71→        .unwrap()
 72→        .work_counter
 73→    };
 74→    let merkle_tree_account = rpc
 75→        .get_account(state_tree_bundle.accounts.merkle_tree)
 76→        .await
 77→        .unwrap()
 78→        .unwrap();
 79→    let state_tree_header: &StateMerkleTreeAccount = bytemuck::from_bytes(
 80→        &merkle_tree_account.data[8..8 + std::mem::size_of::<StateMerkleTreeAccount>()],
 81→    );
 82→    let network_fee = state_tree_header.metadata.rollover_metadata.network_fee;
 83→
 84→    let pre_merkle_tree_lamports = rpc
 85→        .get_account(state_tree_bundle.accounts.merkle_tree)
 86→        .await
 87→        .unwrap()
 88→        .unwrap()
 89→        .lamports;
 90→
 91→    let onchain_merkle_tree =
 92→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
 93→            rpc,
 94→            state_tree_bundle.accounts.merkle_tree,
 95→        )
 96→        .await
 97→        .unwrap();
 98→    assert_eq!(
 99→        onchain_merkle_tree.root(),
100→        state_tree_bundle.merkle_tree.root()
101→    );
102→    let pre_root = onchain_merkle_tree.root();
103→    let change_log_index = onchain_merkle_tree.changelog_index() as u64;
104→
105→    let mut compressed_account_to_nullify = Vec::new();
106→
107→    let first = nullifier_queue.first_no_seq().unwrap();
108→
109→    for i in 0..nullifier_queue.get_capacity() {
110→        let bucket = nullifier_queue.get_bucket(i).unwrap();
111→        if let Some(bucket) = bucket {
112→            if bucket.sequence_number.is_none() {
113→                debug!("element to nullify: {:?}", bucket.value_bytes());
114→                let leaf_index: usize = state_tree_bundle
115→                    .merkle_tree
116→                    .get_leaf_index(&bucket.value_bytes())
117→                    .unwrap();
118→                debug!("leaf_index: {:?}", leaf_index);
119→                compressed_account_to_nullify.push((i, bucket.value_bytes()));
120→            }
121→        }
122→    }
123→
124→    debug!(
125→        "nullifying {:?} accounts ",
126→        compressed_account_to_nullify.len()
127→    );
128→
129→    for (i, (index_in_nullifier_queue, compressed_account)) in
130→        compressed_account_to_nullify.iter().enumerate()
131→    {
132→        let leaf_index: usize = state_tree_bundle
133→            .merkle_tree
134→            .get_leaf_index(compressed_account)
135→            .unwrap();
136→        debug!("nullifying leaf: {:?}", leaf_index);
137→
138→        let proof: Vec<[u8; 32]> = state_tree_bundle
139→            .merkle_tree
140→            .get_proof_of_leaf(leaf_index, false)
141→            .unwrap();
142→        let ix = create_nullify_instruction(
143→            CreateNullifyInstructionInputs {
144→                authority: forester.pubkey(),
145→                nullifier_queue: state_tree_bundle.accounts.nullifier_queue,
146→                merkle_tree: state_tree_bundle.accounts.merkle_tree,
147→                change_log_indices: vec![change_log_index],
148→                leaves_queue_indices: vec![*index_in_nullifier_queue as u16],
149→                indices: vec![leaf_index as u64],
150→                proofs: vec![proof],
151→                derivation: forester.pubkey(),
152→                is_metadata_forester,
153→            },
154→            epoch,
155→        );
156→        let instructions = [ix];
157→
158→        let event = Rpc::create_and_send_transaction_with_event::<MerkleTreeEvent>(
159→            rpc,
160→            &instructions,
161→            &forester.pubkey(),
162→            &[forester],
163→        )
164→        .await?
165→        .unwrap();
166→
167→        match event.0 {
168→            MerkleTreeEvent::V2(event) => {
169→                assert_eq!(event.id, state_tree_bundle.accounts.merkle_tree.to_bytes());
170→                assert_eq!(
171→                    event.seq,
172→                    onchain_merkle_tree.sequence_number() as u64 + 1 + i as u64
173→                );
174→                assert_eq!(event.nullified_leaves_indices.len(), 1);
175→                assert_eq!(event.nullified_leaves_indices[0], leaf_index as u64);
176→            }
177→            _ => {
178→                panic!("Wrong event type.");
179→            }
180→        }
181→
182→        assert_value_is_marked_in_queue(
183→            rpc,
184→            state_tree_bundle,
185→            index_in_nullifier_queue,
186→            compressed_account,
187→        )
188→        .await;
189→    }
190→
191→    let num_nullified = compressed_account_to_nullify.len() as u64;
192→    // Locally nullify all leaves
193→    for (_, compressed_account) in compressed_account_to_nullify.iter() {
194→        let leaf_index = state_tree_bundle
195→            .merkle_tree
196→            .get_leaf_index(compressed_account)
197→            .unwrap();
198→        debug!("locally nullifying leaf_index {}", leaf_index);
199→        debug!("compressed_account {:?}", compressed_account);
200→        debug!(
201→            "merkle tree pubkey {:?}",
202→            state_tree_bundle.accounts.merkle_tree
203→        );
204→
205→        state_tree_bundle
206→            .merkle_tree
207→            .update(&[0u8; 32], leaf_index)
208→            .unwrap();
209→    }
210→    let onchain_merkle_tree =
211→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
212→            rpc,
213→            state_tree_bundle.accounts.merkle_tree,
214→        )
215→        .await
216→        .unwrap();
217→    assert_eq!(
218→        onchain_merkle_tree.root(),
219→        state_tree_bundle.merkle_tree.root()
220→    );
221→    if !is_metadata_forester {
222→        assert_forester_counter(
223→            rpc,
224→            &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
225→            pre_forester_counter,
226→            num_nullified,
227→        )
228→        .await
229→        .unwrap();
230→    }
231→
232→    // Assert network fee reimbursement from merkle tree to forester.
233→    // V1 state tree network fees accumulate in the merkle tree account.
234→    if network_fee > 0 && num_nullified > 0 {
235→        let post_merkle_tree_lamports = rpc
236→            .get_account(state_tree_bundle.accounts.merkle_tree)
237→            .await
238→            .unwrap()
239→            .unwrap()
240→            .lamports;
241→        assert_eq!(
242→            pre_merkle_tree_lamports - post_merkle_tree_lamports,
243→            num_nullified * network_fee,
244→            "Merkle tree should have paid network_fee * num_nullified to forester"
245→        );
246→    }
247→
248→    // SAFEGUARD: check that the root changed if there was at least one element to nullify
249→    if first.is_some() {
250→        assert_ne!(pre_root, onchain_merkle_tree.root());
251→    }
252→    Ok(())
253→}
