288→    rpc: &mut R,
289→    pubkey: &Pubkey,
290→    pre: u64,
291→    num_nullified: u64,
292→) -> Result<(), RpcError> {
293→    let account = rpc
294→        .get_anchor_account::<ForesterEpochPda>(pubkey)
295→        .await?
296→        .unwrap();
297→    if account.work_counter != pre + num_nullified {
298→        debug!("account.work_counter: {}", account.work_counter);
299→        debug!("pre: {}", pre);
300→        debug!("num_nullified: {}", num_nullified);
301→        debug!("forester pubkey: {:?}", pubkey);
302→        return Err(RpcError::CustomError(
303→            "ForesterEpochPda counter not updated correctly".to_string(),
304→        ));
305→    }
306→    Ok(())
307→}
