314→/// Mocks the address insert logic of a forester.
315→/// Gets addresses from the AddressQueue and inserts them into the AddressMerkleTree.
316→///
317→/// Checks:
318→/// 1. Element has been marked correctly
319→/// 2. Merkle tree has been updated correctly
320→///
321→/// TODO: Event has been emitted, event doesn't exist yet
322→pub async fn empty_address_queue_test<R: Rpc>(
323→    forester: &Keypair,
324→    rpc: &mut R,
325→    address_tree_bundle: &mut AddressMerkleTreeBundle,
326→    signer_is_owner: bool,
327→    epoch: u64,
328→    is_metadata_forester: bool,
329→) -> Result<(), RelayerUpdateError> {
330→    let address_merkle_tree_pubkey = address_tree_bundle.accounts.merkle_tree;
331→    let address_queue_pubkey = address_tree_bundle.accounts.queue;
332→    let initial_merkle_tree_state = address_tree_bundle
333→        .get_v1_indexed_merkle_tree()
334→        .unwrap()
335→        .clone();
336→    let initial_indexed_array_state = address_tree_bundle.indexed_array_v1().unwrap().clone();
337→    let mut update_errors: Vec<RpcError> = Vec::new();
338→    let address_merkle_tree =
339→        get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
340→            rpc,
341→            address_merkle_tree_pubkey,
342→        )
343→        .await
344→        .unwrap();
345→    let indexed_changelog_index = address_merkle_tree.indexed_changelog_index() as u16;
346→    let changelog_index = address_merkle_tree.changelog_index() as u16;
347→
348→    let address_tree_account = rpc
349→        .get_account(address_merkle_tree_pubkey)
350→        .await
351→        .map_err(|_| RelayerUpdateError::RpcError)?
352→        .ok_or(RelayerUpdateError::RpcError)?;
353→    let address_tree_header: &AddressMerkleTreeAccount = bytemuck::from_bytes(
354→        &address_tree_account.data[8..8 + std::mem::size_of::<AddressMerkleTreeAccount>()],
355→    );
356→    let network_fee = address_tree_header.metadata.rollover_metadata.network_fee;
357→
358→    let mut counter = 0;
359→    loop {
360→        let pre_forester_counter = if !signer_is_owner {
361→            rpc.get_anchor_account::<ForesterEpochPda>(
362→                &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
363→            )
364→            .await
365→            .map_err(|e| RelayerUpdateError::RpcError)?
366→            .unwrap()
367→            .work_counter
368→        } else {
369→            0
370→        };
371→        let address_merkle_tree =
372→            get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
373→                rpc,
374→                address_merkle_tree_pubkey,
375→            )
376→            .await
377→            .unwrap();
378→        assert_eq!(address_tree_bundle.root(), address_merkle_tree.root());
379→        let address_queue =
380→            unsafe { get_hash_set::<QueueAccount, R>(rpc, address_queue_pubkey).await }.unwrap();
381→
382→        let address = address_queue.first_no_seq().unwrap();
383→
384→        if address.is_none() {
385→            break;
386→        }
387→        let (address, address_hashset_index) = address.unwrap();
388→        // Create new element from the dequeued value.
389→        let (old_low_address, old_low_address_next_value) = initial_indexed_array_state
390→            .find_low_element_for_nonexistent(&address.value_biguint())
391→            .unwrap();
392→        let address_bundle = initial_indexed_array_state
393→            .new_element_with_low_element_index(old_low_address.index, &address.value_biguint())
394→            .unwrap();
395→
396→        // Get the Merkle proof for updating low element.
397→        let low_address_proof = initial_merkle_tree_state
398→            .get_proof_of_leaf(old_low_address.index, false)
399→            .unwrap();
400→
401→        let old_sequence_number = address_merkle_tree.sequence_number();
402→        let old_root = address_merkle_tree.root();
403→
404→        let pre_queue_lamports = if network_fee > 0 {
405→            rpc.get_account(address_queue_pubkey)
406→                .await
407→                .map_err(|_| RelayerUpdateError::RpcError)?
408→                .ok_or(RelayerUpdateError::RpcError)?
409→                .lamports
410→        } else {
411→            0
412→        };
413→
414→        // Update on-chain tree.
415→        let update_successful = match update_merkle_tree(
416→            rpc,
417→            forester,
418→            address_queue_pubkey,
419→            address_merkle_tree_pubkey,
420→            address_hashset_index,
421→            old_low_address.index as u64,
422→            bigint_to_be_bytes_array(&old_low_address.value).unwrap(),
423→            old_low_address.next_index as u64,
424→            bigint_to_be_bytes_array(&old_low_address_next_value).unwrap(),
425→            low_address_proof.to_array().unwrap(),
426→            Some(changelog_index),
427→            Some(indexed_changelog_index),
428→            signer_is_owner,
429→            epoch,
430→            is_metadata_forester,
431→        )
432→        .await
433→        {
434→            Ok(event) => {
435→                let event = event.unwrap();
436→                match event.0 {
437→                    MerkleTreeEvent::V3(event) => {
438→                        // Only assert for the first update since the other updates might be patched
439→                        // the asserts are likely to fail
440→                        if counter == 0 {
441→                            assert_eq!(event.id, address_merkle_tree_pubkey.to_bytes());
442→                            assert_eq!(event.seq, old_sequence_number as u64 + 1);
443→                            assert_eq!(event.updates.len(), 1);
444→                            let event = &event.updates[0];
445→                            assert_eq!(
446→                                event.new_low_element.index, address_bundle.new_low_element.index,
447→                                "Empty Address Queue Test: invalid new_low_element.index"
448→                            );
449→                            assert_eq!(
450→                                event.new_low_element.next_index,
451→                                address_bundle.new_low_element.next_index,
452→                                "Empty Address Queue Test: invalid new_low_element.next_index"
453→                            );
454→                            assert_eq!(
455→                                event.new_low_element.value,
456→                                bigint_to_be_bytes_array::<32>(
457→                                    &address_bundle.new_low_element.value
458→                                )
459→                                .unwrap(),
460→                                "Empty Address Queue Test: invalid new_low_element.value"
461→                            );
462→                            assert_eq!(
463→                                event.new_low_element.next_value,
464→                                bigint_to_be_bytes_array::<32>(&address_bundle.new_element.value)
465→                                    .unwrap(),
466→                                "Empty Address Queue Test: invalid new_low_element.next_value"
467→                            );
468→                            let leaf_hash = address_bundle
469→                                .new_low_element
470→                                .hash::<Poseidon>(&address_bundle.new_element.value)
471→                                .unwrap();
472→                            assert_eq!(
473→                                event.new_low_element_hash, leaf_hash,
474→                                "Empty Address Queue Test: invalid new_low_element_hash"
475→                            );
476→                            let leaf_hash = address_bundle
477→                                .new_element
478→                                .hash::<Poseidon>(&address_bundle.new_element_next_value)
479→                                .unwrap();
480→                            assert_eq!(
481→                                event.new_high_element_hash, leaf_hash,
482→                                "Empty Address Queue Test: invalid new_high_element_hash"
483→                            );
484→                            assert_eq!(
485→                                event.new_high_element.index, address_bundle.new_element.index,
486→                                "Empty Address Queue Test: invalid new_high_element.index"
487→                            );
488→                            assert_eq!(
489→                                event.new_high_element.next_index,
490→                                address_bundle.new_element.next_index,
491→                                "Empty Address Queue Test: invalid new_high_element.next_index"
492→                            );
493→                            assert_eq!(
494→                                event.new_high_element.value,
495→                                bigint_to_be_bytes_array::<32>(&address_bundle.new_element.value)
496→                                    .unwrap(),
497→                                "Empty Address Queue Test: invalid new_high_element.value"
498→                            );
499→                            assert_eq!(
500→                                event.new_high_element.next_value,
501→                                bigint_to_be_bytes_array::<32>(
502→                                    &address_bundle.new_element_next_value
503→                                )
504→                                .unwrap(),
505→                                "Empty Address Queue Test: invalid new_high_element.next_value"
506→                            );
507→                        }
508→                    }
509→                    _ => {
510→                        panic!("Wrong event type.");
511→                    }
512→                }
513→                counter += 1;
514→                true
515→            }
516→            Err(e) => {
517→                update_errors.push(e);
518→                break;
519→            }
520→        };
521→
522→        if update_successful {
523→            if !signer_is_owner {
524→                assert_forester_counter(
525→                    rpc,
526→                    &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
527→                    pre_forester_counter,
528→                    1,
529→                )
530→                .await
531→                .unwrap();
532→            }
533→
534→            // Assert network fee reimbursement from queue to forester.
535→            // Only when going through registry (!signer_is_owner) since
536→            // the signer_is_owner path passes fee_payer: None.
537→            if network_fee > 0 && !signer_is_owner {
538→                let post_queue_lamports = rpc
539→                    .get_account(address_queue_pubkey)
540→                    .await
541→                    .map_err(|_| RelayerUpdateError::RpcError)?
542→                    .ok_or(RelayerUpdateError::RpcError)?
543→                    .lamports;
544→                assert_eq!(
545→                    pre_queue_lamports - post_queue_lamports,
546→                    network_fee,
547→                    "Address queue should have paid network_fee to forester"
548→                );
549→            }
550→
551→            let merkle_tree =
552→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
553→                    rpc,
554→                    address_merkle_tree_pubkey,
555→                )
556→                .await
557→                .unwrap();
558→
559→            let (old_low_address, _) = address_tree_bundle
560→                .find_low_element_for_nonexistent(&address.value_biguint())
561→                .unwrap();
562→            let address_bundle = address_tree_bundle
563→                .new_element_with_low_element_index(old_low_address.index, &address.value_biguint())
564→                .unwrap();
565→            let address_queue =
566→                unsafe { get_hash_set::<QueueAccount, R>(rpc, address_queue_pubkey).await }
567→                    .unwrap();
568→
569→            assert_eq!(
570→                address_queue
571→                    .get_bucket(address_hashset_index as usize)
572→                    .unwrap()
573→                    .unwrap()
574→                    .sequence_number()
575→                    .unwrap(),
576→                old_sequence_number + address_queue.sequence_threshold + 2 // We are doing two Merkle tree operations
577→            );
578→
579→            address_tree_bundle
580→                .update(
581→                    &address_bundle.new_low_element,
582→                    &address_bundle.new_element,
583→                    &address_bundle.new_element_next_value,
584→                )
585→                .unwrap();
586→            address_tree_bundle
587→                .append_with_low_element_index(
588→                    address_bundle.new_low_element.index,
589→                    &address_bundle.new_element.value,
590→                )
591→                .unwrap();
592→            assert_eq!(merkle_tree.sequence_number(), old_sequence_number + 2);
593→            assert_ne!(old_root, merkle_tree.root(), "Root did not change.");
594→            assert_eq!(
595→                address_tree_bundle.root(),
596→                merkle_tree.root(),
597→                "Root off-chain onchain inconsistent."
598→            );
599→
600→            let changelog_entry = merkle_tree
601→                .changelog
602→                .get(merkle_tree.changelog_index())
603→                .unwrap();
604→            let path = address_tree_bundle
605→                .get_path_of_leaf(merkle_tree.current_index(), true)
606→                .unwrap();
607→            for (i, path_node) in path.iter().enumerate() {
608→                let changelog_node = changelog_entry.path[i].unwrap();
609→                assert_eq!(changelog_node, *path_node);
610→            }
611→
612→            let indexed_changelog_entry = merkle_tree
613→                .indexed_changelog
614→                .get(merkle_tree.indexed_changelog_index())
615→                .unwrap();
616→            let proof = address_tree_bundle
617→                .get_proof_of_leaf(merkle_tree.current_index(), false)
618→                .unwrap();
619→            assert_eq!(
620→                address_bundle.new_element,
621→                indexed_changelog_entry.element.into(),
622→            );
623→            assert_eq!(indexed_changelog_entry.proof.as_slice(), proof.as_slice());
624→            assert_eq!(
625→                indexed_changelog_entry.changelog_index,
626→                merkle_tree.changelog_index()
627→            );
628→        }
629→    }
630→
631→    if update_errors.is_empty() {
632→        Ok(())
633→    } else {
634→        panic!("Errors: {:?}", update_errors);
635→    }
636→}
