638→#[allow(clippy::too_many_arguments)]
639→pub async fn update_merkle_tree<R: Rpc>(
640→    rpc: &mut R,
641→    forester: &Keypair,
642→    address_queue_pubkey: Pubkey,
643→    address_merkle_tree_pubkey: Pubkey,
644→    value: u16,
645→    low_address_index: u64,
646→    low_address_value: [u8; 32],
647→    low_address_next_index: u64,
648→    low_address_next_value: [u8; 32],
649→    low_address_proof: [[u8; 32]; 16],
650→    changelog_index: Option<u16>,
651→    indexed_changelog_index: Option<u16>,
652→    signer_is_owner: bool,
653→    epoch: u64,
654→    is_metadata_forester: bool,
655→) -> Result<Option<(MerkleTreeEvent, Signature, u64)>, RpcError> {
656→    let changelog_index = match changelog_index {
657→        Some(changelog_index) => changelog_index,
658→        None => {
659→            let address_merkle_tree =
660→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
661→                    rpc,
662→                    address_merkle_tree_pubkey,
663→                )
664→                .await
665→                .unwrap();
666→
667→            address_merkle_tree.changelog_index() as u16
668→        }
669→    };
670→    let indexed_changelog_index = match indexed_changelog_index {
671→        Some(indexed_changelog_index) => indexed_changelog_index,
672→        None => {
673→            let address_merkle_tree =
674→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
675→                    rpc,
676→                    address_merkle_tree_pubkey,
677→                )
678→                .await
679→                .unwrap();
680→
681→            address_merkle_tree.indexed_changelog_index() as u16
682→        }
683→    };
684→    let update_ix = if !signer_is_owner {
685→        create_update_address_merkle_tree_instruction(
686→            UpdateAddressMerkleTreeInstructionInputs {
687→                authority: forester.pubkey(),
688→                derivation: forester.pubkey(),
689→                address_merkle_tree: address_merkle_tree_pubkey,
690→                address_queue: address_queue_pubkey,
691→                changelog_index,
692→                indexed_changelog_index,
693→                value,
694→                low_address_index,
695→                low_address_value,
696→                low_address_next_index,
697→                low_address_next_value,
698→                low_address_proof,
699→                is_metadata_forester,
700→            },
701→            epoch,
702→        )
703→    } else {
704→        let instruction_data = UpdateAddressMerkleTree {
705→            changelog_index,
706→            indexed_changelog_index,
707→            value,
708→            low_address_index,
709→            low_address_value,
710→            low_address_next_index,
711→            low_address_next_value,
712→            low_address_proof,
713→        };
714→        Instruction {
715→            program_id: ID,
716→            accounts: vec![
717→                AccountMeta::new(forester.pubkey(), true),
718→                AccountMeta::new(ID, false),
719→                AccountMeta::new(address_queue_pubkey, false),
720→                AccountMeta::new(address_merkle_tree_pubkey, false),
721→                AccountMeta::new(NOOP_PROGRAM_ID, false),
722→                AccountMeta::new(ID, false),
723→            ],
724→            data: instruction_data.data(),
725→        }
726→    };
727→
728→    rpc.create_and_send_transaction_with_event::<MerkleTreeEvent>(
729→        &[update_ix],
730→        &forester.pubkey(),
731→        &[forester],
732→    )
733→    .await
734→}
