124→pub fn create_rollover_address_merkle_tree_instruction(
125→    inputs: CreateRolloverMerkleTreeInstructionInputs,
126→    epoch: u64,
127→) -> Instruction {
128→    let (_, bump) = get_cpi_authority_pda();
129→
130→    let instruction_data = crate::instruction::RolloverAddressMerkleTreeAndQueue { bump };
131→    let (cpi_authority, _) = get_cpi_authority_pda();
132→    let registered_program_pda = get_registered_program_pda(&crate::ID);
133→    let registered_forester_pda = if inputs.is_metadata_forester {
134→        None
135→    } else {
136→        Some(get_forester_epoch_pda_from_authority(&inputs.derivation, epoch).0)
137→    };
